377	        );
378	      }
379	
380	      const externalId = parsed.team_id ?? parsed.user_id;
381	      const now = new Date().toISOString();
382	
383	      const accountInfo = {
384	        version: 1 as const,
385	        sourceType: "vercel" as const,
386	        events: [
387	          "deployment.created",
388	          "deployment.ready",
389	          "deployment.succeeded",
390	          "deployment.error",
391	          "deployment.canceled",
