1	/**
2	 * Process OAuth callback — the heavyweight OAuth completion logic.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (lines 208-489).
5	 * Returns structured CallbackProcessResult instead of HTTP responses.
6	 * The Route Handler maps CallbackProcessResult to NextResponse.redirect / HTML.
7	 */
8	import { db } from "@db/app/client";
9	import { gatewayInstallations, pendingInstallations } from "@db/app/schema";
10	import type { SourceType } from "@repo/app-providers";
11	import {
12	  getProvider,
13	  githubAppInstallationSchema,
14	  providerAccountInfoSchema,
15	} from "@repo/app-providers";
16	import { and, eq } from "@vendor/db";
17	import { log } from "@vendor/observability/log/next";
18	import { providerConfigs } from "../provider-configs";
19	import { writeTokenRecord } from "../token-store";
20	import { consumeOAuthState, storeOAuthResult } from "./state";
21	
22	// ── App URL ──
23	
24	/**
25	 * App URL for redirects.
26	 */
27	const appUrl = (() => {
28	  const vercelEnv = process.env.VERCEL_ENV;
29	  const vercelUrl = process.env.VERCEL_URL;
30	  const productionUrl = process.env.VERCEL_PROJECT_PRODUCTION_URL;
31	
32	  if (vercelEnv === "preview" && vercelUrl) {
33	    return `https://${vercelUrl}`;
34	  }
35	
36	  if (productionUrl) {
37	    return `https://${productionUrl}`;
38	  }
39	
40	  return "http://localhost:3024";
41	})();
42	
43	// ── Result Types ──
44	
45	/**
46	 * Structured result from processing an OAuth callback.
47	 * The Route Handler maps this to NextResponse.redirect() or HTML response.
48	 */
49	export type CallbackProcessResult =
50	  | { kind: "redirect"; url: string }
51	  | { kind: "inline_html"; html: string; status?: number }
52	  | { kind: "error"; error: string; status: number };
53	
54	// ── Inline HTML Templates ──
55	
56	function successHtml(providerName: string): string {
57	  return `<!doctype html>
58	<html>
59	  <head><title>Connected</title></head>
60	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
61	    <div style="text-align:center">
62	      <div style="font-size:48px;margin-bottom:16px">&#10003;</div>
63	      <h1 style="margin:0 0 8px">Connected to ${providerName}!</h1>
64	      <p style="color:#666">You can close this tab and return to your terminal.</p>
65	    </div>
66	    <script>setTimeout(()=>window.close(),2000)</script>
67	  </body>
68	</html>`;
69	}
70	
71	function errorHtml(message: string): string {
72	  return `<!doctype html>
73	<html>
74	  <head><title>Connection Failed</title></head>
75	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
76	    <div style="text-align:center">
77	      <div style="font-size:48px;margin-bottom:16px">&#10007;</div>
78	      <h1 style="margin:0 0 8px">Connection Failed</h1>
79	      <p style="color:#666">${message}</p>
80	      <p style="color:#999;font-size:14px">Close this tab and try again in your terminal.</p>
81	    </div>
82	  </body>
83	</html>`;
84	}
85	
86	// ── Redirect Helpers ──
87	
88	function buildRedirectForCompletion(
89	  stateData: Record<string, string>,
90	  providerName: SourceType,
91	  opts: { reactivated?: boolean; setupAction?: string }
92	): CallbackProcessResult {
93	  const redirectTo = stateData.redirectTo;
94	
95	  if (redirectTo === "inline") {
96	    return { kind: "inline_html", html: successHtml(providerName) };
97	  }
98	
99	  if (redirectTo) {
100	    const redirectUrl = new URL(redirectTo);
101	    if (opts.reactivated) {
102	      redirectUrl.searchParams.set("reactivated", "true");
103	    }
104	    if (opts.setupAction) {
105	      redirectUrl.searchParams.set("setup_action", opts.setupAction);
106	    }
107	    return { kind: "redirect", url: redirectUrl.toString() };
108	  }
109	
110	  // Default: redirect to app (existing behavior, backwards compatible)
111	  const redirectUrl = new URL(`${appUrl}/provider/${providerName}/connected`);
112	  if (opts.reactivated) {
113	    redirectUrl.searchParams.set("reactivated", "true");
114	  }
115	  if (opts.setupAction) {
116	    redirectUrl.searchParams.set("setup_action", opts.setupAction);
117	  }
118	  return { kind: "redirect", url: redirectUrl.toString() };
119	}
120	
121	function buildRedirectForError(
122	  stateData: Record<string, string>,
123	  providerName: SourceType,
124	  message: string
125	): CallbackProcessResult {
126	  const redirectTo = stateData.redirectTo;
127	
128	  if (redirectTo === "inline") {
129	    return { kind: "inline_html", html: errorHtml(message), status: 400 };
130	  }
131	
132	  if (redirectTo) {
133	    return {
134	      kind: "redirect",
135	      url: `${redirectTo}?error=${encodeURIComponent(message)}`,
136	    };
137	  }
138	
139	  return {
140	    kind: "redirect",
141	    url: `${appUrl}/provider/${providerName}/connected?error=${encodeURIComponent(message)}`,
142	  };
143	}
144	
145	// ── GitHub Org Info Resolution ──
146	
147	interface GitHubOrgInfo {
148	  accountAvatarUrl?: string;
149	  accountId: string;
150	  accountLogin: string;
151	}
152	
153	/**
154	 * Fetch GitHub org info (account.id, login, avatar_url) for an installation
155	 * using the GitHub App JWT. Only works for GitHub provider with app-token auth.
156	 */
157	async function resolveGitHubOrgInfo(
158	  providerName: SourceType,
159	  externalId: string,
160	  getAppToken: (config: never) => Promise<string>,
161	  config: unknown
162	): Promise<GitHubOrgInfo | null> {
163	  if (providerName !== "github") {
164	    return null;
165	  }
166	
167	  const jwt = await getAppToken(config as never);
168	  const response = await fetch(
169	    `https://api.github.com/app/installations/${externalId}`,
170	    {
171	      headers: {
172	        Authorization: `Bearer ${jwt}`,
173	        Accept: "application/vnd.github+json",
174	        "X-GitHub-Api-Version": "2022-11-28",
175	      },
176	      signal: AbortSignal.timeout(10_000),
177	    }
178	  );
179	
180	  if (!response.ok) {
181	    throw new Error(
182	      `GitHub API error: ${response.status} ${response.statusText}`
183	    );
184	  }
185	
186	  const data = githubAppInstallationSchema.parse(await response.json());
187	  if (!data.account) {
188	    throw new Error("GitHub installation has no account");
189	  }
190	
191	  return {
192	    accountId: String(data.account.id),
193	    accountLogin: data.account.login,
194	    accountAvatarUrl: data.account.avatar_url,
195	  };
196	}
197	
198	// ── Main Callback Processing ──
199	
200	export interface ProcessCallbackParams {
201	  provider: SourceType;
202	  /** All query params from the callback URL */
203	  query: Record<string, string>;
204	  /** The state token from the callback query string */
205	  state: string;
206	}
207	
208	/**
209	 * Process an OAuth callback: validate state, exchange code, upsert installation,
210	 * persist tokens, and return a structured result for the Route Handler to act on.
211	 */
212	export async function processOAuthCallback(
213	  params: ProcessCallbackParams
214	): Promise<CallbackProcessResult> {
215	  const { provider: providerName, state, query } = params;
216	
217	  const providerDef = getProvider(providerName);
218	  const config = providerConfigs[providerName];
219	
220	  if (!config) {
221	    log.warn("[oauth/callback] provider not configured", {
222	      provider: providerName,
223	    });
224	    return {
225	      kind: "error",
226	      error: "unknown_provider",
227	      status: 400,
228	    };
229	  }
230	
231	  let stateData = await consumeOAuthState(state);
232	
233	  // GitHub-initiated redirects (permission changes, reinstalls) arrive without
234	  // our state token. If state is missing but installation_id is present, look up
235	  // the existing installation to recover orgId/connectedBy.
236	  if (!stateData && providerName === "github") {
237	    const installationId = query.installation_id;
238	    if (installationId) {
239	      const existing = await db
240	        .select({
241	          orgId: gatewayInstallations.orgId,
242	          connectedBy: gatewayInstallations.connectedBy,
243	        })
244	        .from(gatewayInstallations)
245	        .where(
246	          and(
247	            eq(gatewayInstallations.provider, "github"),
248	            eq(gatewayInstallations.externalId, installationId)
249	          )
250	        )
251	        .limit(1);
252	
253	      const row = existing[0];
254	      if (row) {
255	        stateData = {
256	          provider: "github",
257	          orgId: row.orgId,
258	          connectedBy: row.connectedBy,
259	        };
260	      }
261	    }
262	  }
263	
264	  if (!stateData) {
265	    log.warn("[oauth/callback] invalid or expired state", {
266	      provider: providerName,
267	      state: state ? `${state.slice(0, 8)}...` : "empty",
268	    });
269	    return {
270	      kind: "error",
271	      error: "invalid_or_expired_state",
272	      status: 400,
273	    };
274	  }
275	
276	  if (stateData.provider !== providerName) {
277	    log.warn("[oauth/callback] state provider mismatch", {
278	      provider: providerName,
279	      stateProvider: stateData.provider,
280	    });
281	    return {
282	      kind: "error",
283	      error: "invalid_or_expired_state",
284	      status: 400,
285	    };
286	  }
287	
288	  const orgId = stateData.orgId ?? "";
289	  const connectedBy = stateData.connectedBy ?? "unknown";
290	
291	  try {
292	    const auth = providerDef.auth;
293	    if (auth.kind !== "oauth" && auth.kind !== "app-token") {
294	      log.warn("[oauth/callback] provider does not support OAuth callback", {
295	        provider: providerName,
296	        authKind: auth.kind,
297	      });
298	      return {
299	        kind: "error",
300	        error: "provider_does_not_support_oauth",
301	        status: 400,
302	      };
303	    }
304	
305	    // Pure provider logic — no DB, no framework coupling.
306	    // Both OAuthDef and AppTokenDef have processCallback — TypeScript narrows here.
307	    // SAFETY: config is providerConfigs[providerName], created by the same provider's
308	    // createConfig(). Runtime type matches TConfig; the service cannot know TConfig
309	    // statically because it serves all providers from a single Record<string, unknown>.
310	    const result = await auth.processCallback(config as never, query);
311	
312	    // Handle pending-setup: provider needs additional configuration (e.g., GitHub App request flow).
313	    // No installation to upsert — just store the setup action and redirect.
314	    if (result.status === "pending-setup") {
315	      await storeOAuthResult(state, {
316	        status: "completed",
317	        provider: providerName,
318	        setupAction: result.setupAction,
319	      });
320	
321	      log.info("[oauth/callback] pending setup, redirecting", {
322	        provider: providerName,
323	        setupAction: result.setupAction,
324	      });
325	      return buildRedirectForCompletion(stateData, providerName, {
326	        setupAction: result.setupAction,
327	      });
328	    }
329	
330	    // ── Pending install: no orgId → store in pendingInstallations, redirect ──
331	    if (!orgId) {
332	      const getAppToken =
333	        auth.kind === "app-token" && "getAppToken" in auth
334	          ? auth.getAppToken
335	          : undefined;
336	
337	      if (!getAppToken) {
338	        throw new Error(
339	          "Pending install requires app-token auth with getAppToken"
340	        );
341	      }
342	
343	      const githubOrgInfo = await resolveGitHubOrgInfo(
344	        providerName,
345	        result.externalId,
346	        getAppToken,
347	        config
348	      );
349	
350	      if (!githubOrgInfo) {
351	        throw new Error("Could not resolve GitHub organization info");
352	      }
353	
354	      // 1:1 constraint check: reject if this GitHub org is already connected
355	      const existingBinding = await db
356	        .select({ id: gatewayInstallations.id })
357	        .from(gatewayInstallations)
358	        .where(
359	          and(
360	            eq(gatewayInstallations.provider, providerName),
361	            eq(gatewayInstallations.providerOrgId, githubOrgInfo.accountId)
362	          )
363	        )
364	        .limit(1);
365	
366	      if (existingBinding.length > 0) {
367	        throw new Error(
368	          "This GitHub organization is already connected to a workspace"
369	        );
370	      }
371	
372	      const accountInfo = providerAccountInfoSchema.parse(result.accountInfo);
373	
374	      // Upsert pending installation (idempotent on provider + externalId)
375	      await db
