content.content:
1	/**
2	 * GET /api/connect/:provider/callback
3	 *
4	 * OAuth callback. Ported from apps/gateway/src/routes/connections.ts (lines 208-489).
5	 *
6	 * NOT tRPC — OAuth provider redirects here directly (browser).
7	 * Maps CallbackProcessResult from the lib layer to HTTP responses.
8	 */
9	
10	import {
11	  type CallbackProcessResult,
12	  processOAuthCallback,
13	} from "@api/platform/lib/oauth/callback";
14	import type { SourceType } from "@repo/app-providers";
15	import { log } from "@vendor/observability/log/next";
16	import { type NextRequest, NextResponse } from "next/server";
17	
18	export const runtime = "nodejs";
19	
20	export async function GET(
21	  req: NextRequest,
22	  { params }: { params: Promise<{ provider: string }> }
23	) {
24	  const { provider } = await params;
25	  const providerName = provider as SourceType;
26	
27	  // Build query dict from all URL search params (null-prototype to prevent prototype pollution)
28	  const query: Record<string, string> = Object.assign(
29	    Object.create(null) as Record<string, string>,
30	    Object.fromEntries(req.nextUrl.searchParams)
31	  );
32	
33	  const state = query.state ?? "";
34	
35	  const result: CallbackProcessResult = await processOAuthCallback({
36	    provider: providerName,
37	    state,
38	    query,
39	  });
40	
41	  switch (result.kind) {
42	    case "redirect":
43	      log.info("[oauth/callback] redirecting", { provider: providerName });
44	      return NextResponse.redirect(result.url);
45	
46	    case "inline_html":
47	      log.info("[oauth/callback] inline html response", {
48	        provider: providerName,
49	        status: result.status ?? 200,
50	      });
