53	  const preferNewestRef = useRef(false);
54	  const installationIdsBeforeRef = useRef<Set<string>>(new Set());
55	
56	  // ── OAuth ────────────────────────────────────────────────────────────────
57	  const listInstallationsOpts =
58	    trpc.connections.generic.listInstallations.queryOptions({ provider });
59	  const {
60	    handleConnect: connectOAuth,
61	    isConnecting,
62	    openCustomUrl,
63	  } = useOAuthPopup({
64	    provider,
65	    queryKeysToInvalidate: [
66	      listInstallationsOpts.queryKey,
67	      ["connections", "generic", "listResources"],
68	    ],
69	    onSuccess: () => {
70	      preferNewestRef.current = true;
71	    },
72	  });
73	
74	  const handleConnect = () => {
75	    installationIdsBeforeRef.current = new Set(
76	      state.installations.map((i) => i.id)
77	    );
78	    void connectOAuth();
79	  };
80	
81	  const customConnectUrl =
82	    provider === "github"
83	      ? (data: { url: string; state: string }) =>
84	          `https://github.com/apps/${env.NEXT_PUBLIC_GITHUB_APP_SLUG}/installations/select_target?state=${data.state}`
85	      : undefined;
86	
87	  const handleAdjustPermissions =
88	    customConnectUrl && openCustomUrl
89	      ? () => {
90	          installationIdsBeforeRef.current = new Set(
91	            state.installations.map((i) => i.id)
92	          );
93	          void openCustomUrl(customConnectUrl);
94	        }
95	      : null;
96	
97	  // ── Connection query ─────────────────────────────────────────────────────
98	  const { data: connectionData } = useSuspenseQuery(
99	    trpc.connections.generic.listInstallations.queryOptions({ provider })
100	  );
101	
102	  const { installationMode, resourceLabel, installations } = connectionData;
103	  const hasConnection = installations.length > 0;
104	
105	  // ── Sync installations to context ────────────────────────────────────────
106	  const prevInstallationIdsRef = useRef("");
107	  useEffect(() => {
108	    const newIds = installations.map((i) => i.id).join(",");
109	    if (prevInstallationIdsRef.current !== newIds) {
110	      setInstallations(provider, installations);
111	      prevInstallationIdsRef.current = newIds;
112	    }
113	  }, [installations, provider, setInstallations]);
114	
115	  // ── Auto-select installation ─────────────────────────────────────────────
116	  useEffect(() => {
