255	      <AccordionContent className="px-4">
256	        {hasConnection ? (
257	          <div className="space-y-4 pt-2">
258	            {selectionCount > 0 && !showPicker ? (
259	              <div className="rounded-lg border bg-card p-4">
260	                <div className="flex items-center gap-3">
261	                  <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-primary text-primary-foreground">
