324	                              )}
325	                              {inst.label}
326	                            </div>
327	                          </SelectItem>
328	                        ))}
329	                      </SelectContent>
330	                    </Select>
331	                  )}
332	                  {installationMode === "single" && (
333	                    <div className="flex shrink-0 items-center gap-2 rounded-md border bg-muted/50 px-3 py-2">
334	                      <Icon className="h-3 w-3" />
335	                      <span className="font-medium text-sm">
336	                        {display.displayName}
337	                      </span>
338	                    </div>
339	                  )}
340	                  <div className="relative flex-1">
341	                    <Search className="absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
342	                    <Input
343	                      className="pl-10"
344	                      onChange={(e) => setSearchQuery(e.target.value)}
345	                      placeholder={`Search ${resourceLabel}...`}
346	                      value={searchQuery}
347	                    />
348	                  </div>
349	                </div>
350	
351	                <div className="max-h-[260px] overflow-y-auto rounded-lg border bg-card">
352	                  {resourcesError ? (
353	                    <div className="flex flex-col items-center gap-3 py-6 text-center">
354	                      <p className="text-destructive text-sm">
355	                        Failed to load {resourceLabel}. The connection may need
356	                        to be refreshed.
357	                      </p>
358	                      <Button
359	                        onClick={handleConnect}
360	                        size="sm"
361	                        variant="outline"
362	                      >
363	                        Reconnect {display.displayName}
364	                      </Button>
365	                    </div>
366	                  ) : isLoadingResources ? (
367	                    <div className="p-8 text-center text-muted-foreground">
368	                      <Loader2 className="mx-auto mb-2 h-6 w-6 animate-spin" />
369	                      Loading {resourceLabel}...
370	                    </div>
371	                  ) : filteredResources.length === 0 ? (
372	                    <div className="p-8 text-center text-muted-foreground">
373	                      {searchQuery
374	                        ? `No ${resourceLabel} match your search`
375	                        : `No ${resourceLabel} found`}
376	                    </div>
377	                  ) : (
378	                    <div className="divide-y">
379	                      {filteredResources.map((resource) => (
380	                        <button
381	                          className={`flex w-full cursor-pointer items-center gap-3 p-4 text-left transition-colors hover:bg-accent ${
382	                            selectedIds.has(resource.id) ? "bg-accent/50" : ""
383	                          }`}
384	                          key={resource.id}
385	                          onClick={() => {
