390	                          <Checkbox
391	                            checked={selectedIds.has(resource.id)}
392	                            className="pointer-events-none"
393	                            tabIndex={-1}
394	                          />
395	                          {renderIcon(resource)}
396	                          <div className="min-w-0 flex-1">
397	                            <div className="flex items-center gap-2">
398	                              <span className="truncate font-medium">
399	                                {resource.name}
400	                              </span>
401	                              {resource.badge && (
402	                                <span className="shrink-0 rounded border px-2 py-0.5 text-muted-foreground text-xs">
403	                                  {resource.badge}
404	                                </span>
405	                              )}
406	                            </div>
407	                            {resource.subtitle && (
408	                              <p className="mt-0.5 truncate text-muted-foreground text-xs">
409	                                {resource.subtitle}
410	                              </p>
411	                            )}
412	                          </div>
413	                        </button>
414	                      ))}
415	                    </div>
416	                  )}
417	                </div>
418	
419	                <div className="text-center text-muted-foreground text-sm">
420	                  Missing a {resourceLabel.replace(/s$/, "")}?{" "}
421	                  <button
422	                    className="text-blue-500 underline-offset-4 transition-colors hover:text-blue-600 hover:underline"
423	                    onClick={handleAdjustPermissions ?? handleConnect}
424	                    type="button"
